#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int grid[N][M];
        int K = 1;
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                if (i == 0 || j == 0 || i == N - 1 || j == M - 1) {
                    grid[i][j] = 1;
                } else {
                    grid[i][j] = 2;
                    K = 2;
                }
            }
        }
        printf("%d\n", K);
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                printf("%d ", grid[i][j]);
            }
            printf("\n");
        }
    }
    return 0;
}

